3	import {
4		Sheet,
5		SheetContent,
6		SheetHeader,
7		SheetTitle,
8		SheetTrigger,
9	} from "@workspace/ui/components/sheet";
10	import { Loader2, Scroll, Send } from "lucide-react";
11	import { useCallback, useEffect, useMemo, useRef, useState } from "react";
12	import { Streamdown } from "streamdown";
13	import type { OrganizationCategory } from "@/features/organization-category/get-organization-categories";
14	import type { ChatTodo } from "../todos/get-todos";
15	import { TodoList } from "../todos/todo-list.client";
16	
17	type Message = {
18		id: string;
19		role: "user" | "assistant";
20		content: string;
21	};
22	
23	type OrganizationByCategory = {
24		categoryId: string;
25		description: string;
26		email: string;
27		organizationId: string;
28		name: string;
29		url: string;
30	};
31	
32	export function ChatRoom({
33		categories,
34		chatId,
35		contactEmail,
36		initialConsultedOrgIds,
37		initialMessages,
38		initialTodos,
39		organizationsByCategory,
40	}: {
41		categories: OrganizationCategory[];
42		chatId: string;
43		contactEmail: string | null;
44		initialConsultedOrgIds: string[];
45		initialMessages: Message[];
46		initialTodos: ChatTodo[];
47		organizationsByCategory: OrganizationByCategory[];
48	}) {
49		const [messages, setMessages] = useState<Message[]>(initialMessages);
50		const [input, setInput] = useState("");
51		const [isStreaming, setIsStreaming] = useState(false);
52		const [errorMessage, setErrorMessage] = useState<string | null>(null);
53		const [todos, setTodos] = useState<ChatTodo[]>(initialTodos);
54		const [storedEmail, setStoredEmail] = useState<string | null>(contactEmail);
55		const [consultedOrgIds, setConsultedOrgIds] = useState<string[]>(
56			initialConsultedOrgIds,
57		);
58		const messagesEndRef = useRef<HTMLDivElement | null>(null);
59		const textareaRef = useRef<HTMLTextAreaElement | null>(null);
60		const [isTodoSheetOpen, setIsTodoSheetOpen] = useState(false);
61	
62		const todosFingerprint = useMemo(
63			() =>
64				todos
65					.map(
66						(t) =>
67							`${t.todoId}:${t.title}:${t.description ?? ""}:${t.priority}:${t.suggestedCategoryId ?? ""}`,
68					)
69					.join("|"),
70			[todos],
71		);
72		const [seenFingerprint, setSeenFingerprint] = useState(todosFingerprint);
73		const hasTodoUpdate = todosFingerprint !== seenFingerprint;
74	
75		function handleTodoSheetOpenChange(open: boolean) {
76			setIsTodoSheetOpen(open);
77			if (open) {
78				setSeenFingerprint(todosFingerprint);
79			}
80		}
81	
82		useEffect(() => {
83			messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
84		}, []);
85	
86		// biome-ignore lint/correctness/useExhaustiveDependencies: input 変更後の DOM サイズを反映する
87		useEffect(() => {
88			const el = textareaRef.current;
89			if (!el) return;
90			el.style.height = "auto";
91			el.style.height = `${Math.min(el.scrollHeight, 200)}px`;
92		}, [input]);
93	
94		const refreshTodos = useCallback(async () => {
95			try {
96				const todosRes = await fetch(`/api/chats/${chatId}/todos`, {
97					cache: "no-store",
98				});
99				if (todosRes.ok) {
100					const json = (await todosRes.json()) as { todos: ChatTodo[] };
101					setTodos(json.todos);
102				}
103			} catch {
104				// 失敗しても本流は止めない
105			}
106		}, [chatId]);
107	
108		const refreshConsultedOrgIds = useCallback(async () => {
109			try {
110				const res = await fetch(`/api/chats/${chatId}/consultations`, {
111					cache: "no-store",
112				});
113				if (res.ok) {
114					const json = (await res.json()) as { consultedOrgIds: string[] };
115					setConsultedOrgIds(json.consultedOrgIds);
116				}
117			} catch {
118				// 失敗しても本流は止めない
119			}
120		}, [chatId]);
121	
122		async function handleSubmit(event: React.FormEvent<HTMLFormElement>) {
123			event.preventDefault();
124			const message = input.trim();
125			if (!message || isStreaming) {
126				return;
127			}
128	
129			setErrorMessage(null);
130			setInput("");
131			const userMessageId = crypto.randomUUID();
132			setMessages((prev) => [
133				...prev,
134				{ content: message, id: userMessageId, role: "user" },
135			]);
136	
137			setIsStreaming(true);
138			const assistantId = crypto.randomUUID();
139			setMessages((prev) => [
140				...prev,
141				{ content: "", id: assistantId, role: "assistant" },
142			]);
143	
144			try {
145				const response = await fetch(`/api/chats/${chatId}/messages`, {
146					body: JSON.stringify({ message }),
147					headers: { "content-type": "application/json" },
148					method: "POST",
149				});
150	
151				if (!response.ok || !response.body) {
152					throw new Error("ご返信の取得に失敗しました。");
153				}
154	
155				const reader = response.body.getReader();
156				const decoder = new TextDecoder();
157				let assistantText = "";
158				while (true) {
159					const { done, value } = await reader.read();
160					if (done) {
161						break;
162					}
163					assistantText += decoder.decode(value, { stream: true });
164					setMessages((prev) =>
165						prev.map((m) =>
166							m.id === assistantId ? { ...m, content: assistantText } : m,
167						),
168					);
169				}
170	
171				await refreshTodos();
172			} catch (error) {
173				setErrorMessage(
174					error instanceof Error ? error.message : "ご返信の取得に失敗しました。",
175				);
176				setMessages((prev) => prev.filter((m) => m.id !== assistantId));
177			} finally {
178				setIsStreaming(false);
179				setTimeout(() => {
180					messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
181				}, 50);
182			}
183		}
184	
185		return (
186			<div className="flex h-full min-h-0 flex-col gap-4">
187				<style>{`
188					@keyframes ink-fade {
189						from { opacity: 0; transform: translateY(4px); filter: blur(2px); }
190						to { opacity: 1; transform: translateY(0); filter: blur(0); }
191					}
192					@keyframes thinking-pulse {
193						0%, 100% { opacity: 0.35; transform: scale(1); }
194						50% { opacity: 1; transform: scale(1.15); }
195					}
196					.ink-message { animation: ink-fade 0.55s ease-out both; }
197					.dot-1 { animation: thinking-pulse 1.2s ease-in-out infinite; }
198					.dot-2 { animation: thinking-pulse 1.2s ease-in-out 0.2s infinite; }
199					.dot-3 { animation: thinking-pulse 1.2s ease-in-out 0.4s infinite; }
200					.chat-scroll::-webkit-scrollbar { width: 4px; }
201					.chat-scroll::-webkit-scrollbar-track { background: transparent; }
202					.chat-scroll::-webkit-scrollbar-thumb { background: rgba(184, 153, 104, 0.3); border-radius: 2px; }
203					.chat-scroll::-webkit-scrollbar-thumb:hover { background: rgba(184, 153, 104, 0.5); }
204				`}</style>
205	
206				<header className="flex shrink-0 items-center justify-between gap-3 border-b border-[#C9A961]/60 px-4 pb-3 sm:px-0">
207					<div className="flex items-center gap-3">
208						<span
209							aria-hidden
210							className="h-7 w-px bg-gradient-to-b from-transparent via-[#A07F40] to-transparent"
211						/>
212						<div className="flex flex-col">
213							<span className="font-[family-name:var(--font-mincho)] text-[0.6rem] tracking-[0.4em] text-[#5C5852]">
214								O M I O K U R I
215							</span>
216							<h1 className="font-[family-name:var(--font-mincho)] text-base leading-tight tracking-wider text-[#1F1B17] sm:text-lg">
217								お見送りサポートチャット
218							</h1>
219						</div>
220					</div>
221	
222					<Sheet onOpenChange={handleTodoSheetOpenChange} open={isTodoSheetOpen}>
223						<SheetTrigger asChild>
224							<button
225								aria-label="これからのことを開く"
226								className="relative inline-flex shrink-0 items-center justify-center rounded-full border border-[#C9A961]/60 bg-[#FFFDF8] p-2.5 text-[#1F1B17] transition hover:bg-[#FAF3E6] lg:hidden"
227								type="button"
228							>
229								<Scroll className="size-4" />
230								{hasTodoUpdate && (
231									<span
232										aria-hidden
233										className="absolute -right-0.5 -top-0.5 size-2.5 rounded-full bg-[#C24A3D] ring-2 ring-[#FFFDF8]"
234									/>
235								)}
236								{hasTodoUpdate && (
237									<span className="sr-only">新しい更新があります</span>
238								)}
239							</button>
240						</SheetTrigger>
241						<SheetContent
242							className="w-[88vw] max-w-[420px] border-l border-[#C9A961]/40 bg-[#FAF7F1] p-3 sm:max-w-[420px]"
243							side="right"
244						>
245							<SheetHeader className="sr-only">
246								<SheetTitle>これからのこと</SheetTitle>
247							</SheetHeader>
248							<div className="h-[calc(100dvh-1.5rem)] [&>div]:h-full">
249								<TodoList
250									categories={categories}
251									chatId={chatId}
252									consultedOrgIds={consultedOrgIds}
253									initialEmail={storedEmail}
254									onConsulted={refreshConsultedOrgIds}
255									onEmailRegistered={(email) => setStoredEmail(email)}
256									onTodosRefresh={refreshTodos}
257									organizationsByCategory={organizationsByCategory}
258									todos={todos}
259								/>
260							</div>
261						</SheetContent>
262					</Sheet>
263				</header>
264	
265				<div className="flex min-h-0 flex-1 flex-col gap-4 lg:flex-row">
266					<section className="relative flex min-h-0 flex-1 flex-col bg-[#FFFDF8]/80 backdrop-blur-sm">
267						<div
268							aria-hidden
269							className="pointer-events-none absolute inset-0 border border-[#D7C49E]/40"
270						/>
271						<span
272							aria-hidden
273							className="pointer-events-none absolute left-2 top-2 size-3 border-l border-t border-[#B89968]/60"
274						/>
275						<span
276							aria-hidden
277							className="pointer-events-none absolute right-2 top-2 size-3 border-r border-t border-[#B89968]/60"
278						/>
279						<span
280							aria-hidden
281							className="pointer-events-none absolute bottom-2 left-2 size-3 border-b border-l border-[#B89968]/60"
282						/>
283						<span
284							aria-hidden
285							className="pointer-events-none absolute bottom-2 right-2 size-3 border-b border-r border-[#B89968]/60"
286						/>
287	
288						<div className="relative flex min-h-0 flex-1 flex-col gap-4 px-5 py-5 sm:px-7 sm:py-6">
289							<div className="chat-scroll flex flex-1 flex-col gap-5 overflow-y-auto px-1 py-2">
290								{messages.length === 0 && (
291									<div className="ink-message flex flex-col gap-4 self-start max-w-[88%]">
292										<div className="flex items-center gap-2">
293											<span className="size-1.5 rounded-full bg-[#B89968]" />
294											<span className="font-[family-name:var(--font-mincho)] text-[0.68rem] tracking-[0.3em] text-[#5C5852]">
295												コ ン シ ェ ル ジ ュ
296											</span>
297										</div>
298										<div className="rounded-sm border-l-2 border-[#B89968]/60 bg-[#FAF3E6]/40 px-5 py-4 font-[family-name:var(--font-sans-jp)] text-[0.92rem] leading-[2.1] text-[#2A2622]">
299											この度は、お越しくださいまして、ありがとうございます。
300											<br />
301											終活や、ご相続のお手続き、そしてその後の暮らしについて、
302											どのようなことでもお話しください。
303											<br />
304											今、お心にかかっていらっしゃることから、お聞かせいただけますでしょうか。
305										</div>
306									</div>
307								)}
308	
309								{messages.map((message) => (
310									<MessageBubble
311										isStreaming={isStreaming}
312										key={message.id}
313										message={message}
314									/>
315								))}
316								<div ref={messagesEndRef} />
317							</div>
318	
319							{errorMessage && (
320								<div
321									className="flex items-start gap-2 border-l-2 border-[#A24A3D] bg-[#FBEDEA]/60 px-4 py-3 text-xs text-[#A24A3D]"
322									role="alert"
323								>
324									<span>{errorMessage}</span>
325								</div>
326							)}
327	
328							<form
329								className="relative flex items-end gap-2 border-t border-[#D7C49E]/30 pt-4"
330								onSubmit={handleSubmit}
331							>
332								<textarea
333									className="max-h-[200px] flex-1 resize-none overflow-y-auto border border-[#D7C49E]/50 bg-[#FFFDF8] px-4 py-2.5 font-[family-name:var(--font-sans-jp)] text-[0.92rem] leading-[1.9] text-[#2A2622] placeholder:text-[#A8A39A] focus:border-[#B89968] focus:outline-none focus:ring-1 focus:ring-[#B89968]/30 disabled:cursor-not-allowed disabled:opacity-60"
334									disabled={isStreaming}
335									onChange={(e) => setInput(e.target.value)}
336									onKeyDown={(e) => {
337										if (e.key === "Enter" && (e.metaKey || e.ctrlKey)) {
338											e.preventDefault();
339											(
340												e.currentTarget.form as HTMLFormElement | null
341											)?.requestSubmit();
342										}
343									}}
344									placeholder="（Cmd / Ctrl + Enter で送信）"
345									ref={textareaRef}
346									rows={1}
347									value={input}
348								/>
349								<button
350									aria-label="送信"
351									className="group relative inline-flex shrink-0 items-center justify-center overflow-hidden border border-[#2A2622] bg-[#2A2622] px-4 py-2.5 text-[#FAF7F1] transition-all duration-300 hover:bg-[#3A332C] disabled:cursor-not-allowed disabled:opacity-50"
352									disabled={isStreaming || input.trim().length === 0}
353									type="submit"
354								>
355									<span className="absolute inset-y-1.5 left-1.5 w-1.5 border-b border-l border-[#B89968]/60 transition-all duration-300 group-hover:w-2.5" />
356									<span className="absolute inset-y-1.5 right-1.5 w-1.5 border-b border-r border-[#B89968]/60 transition-all duration-300 group-hover:w-2.5" />
357									{isStreaming ? (
358										<Loader2 className="size-4 animate-spin" />
359									) : (
360										<Send className="size-4" />
361									)}
362								</button>
363							</form>
364						</div>
365					</section>
366	
367					<aside className="hidden min-h-0 flex-col gap-3 lg:flex lg:w-[360px]">
368						<TodoList
369							categories={categories}
370							chatId={chatId}
371							consultedOrgIds={consultedOrgIds}
372							initialEmail={storedEmail}
373							onConsulted={refreshConsultedOrgIds}
374							onEmailRegistered={(email) => setStoredEmail(email)}
375							onTodosRefresh={refreshTodos}
376							organizationsByCategory={organizationsByCategory}
377							todos={todos}
378						/>
379					</aside>
380				</div>
381			</div>
382		);
383	}
384	
385	function MessageBubble({
386		isStreaming,
387		message,
388	}: {
389		isStreaming: boolean;
390		message: Message;
391	}) {
392		if (message.role === "user") {
393			return (
394				<div className="ink-message flex flex-col items-end gap-1.5 self-end max-w-[82%]">
395					<span className="font-[family-name:var(--font-mincho)] text-[0.6rem] tracking-[0.3em] text-[#5C5852]">
396						あ な た
397					</span>
398					<div className="whitespace-pre-wrap rounded-sm bg-[#5B7B8B] px-5 py-3 font-[family-name:var(--font-sans-jp)] text-[0.92rem] leading-[1.9] text-[#FAF7F1] shadow-[0_1px_0_rgba(91,123,139,0.4)]">
399						{message.content}
400					</div>
401				</div>
402			);
403		}
404	
405		const showThinking = !message.content && isStreaming;
406	
407		return (
408			<div className="ink-message flex flex-col gap-1.5 self-start max-w-[88%]">
409				<div className="flex items-center gap-2">
410					<span className="size-1.5 rounded-full bg-[#B89968]" />
411					<span className="font-[family-name:var(--font-mincho)] text-[0.6rem] tracking-[0.3em] text-[#5C5852]">
412						コ ン シ ェ ル ジ ュ
413					</span>
414				</div>
415				<div className="rounded-sm border-l-2 border-[#B89968]/60 bg-[#FAF3E6]/40 px-5 py-3 font-[family-name:var(--font-sans-jp)] text-[0.92rem] leading-[2.0] text-[#2A2622]">
416					{showThinking ? (
417						<span className="inline-flex items-center gap-1.5 text-[#3A3530]">
418							<span>お言葉を、お受けしております</span>
